<?php
declare(strict_types=1);

function booking_sync_row(int $bookingId):array{$q=db()->prepare("SELECT b.*,m.name meeting_name,m.location_type,m.location_details,c.calendar_type,c.owner_user_id FROM bookings b JOIN booking_meeting_types m ON m.id=b.meeting_type_id JOIN booking_calendars c ON c.id=b.calendar_id WHERE b.id=?");$q->execute([$bookingId]);$b=$q->fetch();if(!$b)throw new RuntimeException('Booking not found for calendar sync.');return $b;}
function booking_sync_users(array $b):array{if($b['calendar_type']==='individual')return array_values(array_filter([(int)($b['assigned_user_id']?:$b['owner_user_id'])]));$q=db()->prepare('SELECT user_id,weight FROM booking_calendar_members WHERE calendar_id=? ORDER BY user_id');$q->execute([$b['calendar_id']]);$members=$q->fetchAll();if(!$members)return array_values(array_filter([(int)($b['assigned_user_id']?:$b['owner_user_id'])]));if($b['calendar_type']==='collective')return array_map(fn($x)=>(int)$x['user_id'],$members);return [(int)($b['assigned_user_id']?:$members[0]['user_id'])];}
function booking_assign_round_robin(int $bookingId):void{$b=booking_sync_row($bookingId);if($b['calendar_type']!=='round_robin'||$b['assigned_user_id'])return;$q=db()->prepare("SELECT m.user_id,m.weight,COUNT(b.id) future_count FROM booking_calendar_members m LEFT JOIN bookings b ON b.assigned_user_id=m.user_id AND b.status='confirmed' AND b.starts_at>=NOW() WHERE m.calendar_id=? GROUP BY m.user_id,m.weight ORDER BY (COUNT(b.id)/GREATEST(m.weight,1)),m.user_id LIMIT 1");$q->execute([$b['calendar_id']]);if($uid=(int)$q->fetchColumn())db()->prepare('UPDATE bookings SET assigned_user_id=? WHERE id=?')->execute([$uid,$bookingId]);}
function booking_ical(array $b,string $uid):string{$start=(new DateTimeImmutable($b['starts_at'],new DateTimeZone($b['timezone'])))->setTimezone(new DateTimeZone('UTC'))->format('Ymd\THis\Z');$end=(new DateTimeImmutable($b['ends_at'],new DateTimeZone($b['timezone'])))->setTimezone(new DateTimeZone('UTC'))->format('Ymd\THis\Z');$esc=fn($s)=>str_replace(["\\","\n",",",";"],["\\\\","\\n","\\,","\\;"],(string)$s);return "BEGIN:VCALENDAR\r\nVERSION:2.0\r\nPRODID:-//OpenCRM//Booking//EN\r\nBEGIN:VEVENT\r\nUID:$uid\r\nDTSTAMP:".gmdate('Ymd\THis\Z')."\r\nDTSTART:$start\r\nDTEND:$end\r\nSUMMARY:".$esc($b['meeting_name'])."\r\nDESCRIPTION:".$esc('Attendee: '.$b['attendee_name'].' '.$b['attendee_email'])."\r\nLOCATION:".$esc($b['meeting_url']?:$b['location_details'])."\r\nEND:VEVENT\r\nEND:VCALENDAR\r\n";}
function booking_provider_payload(array $b,string $provider):array{$start=(new DateTimeImmutable($b['starts_at'],new DateTimeZone($b['timezone'])))->format(DateTimeInterface::RFC3339);$end=(new DateTimeImmutable($b['ends_at'],new DateTimeZone($b['timezone'])))->format(DateTimeInterface::RFC3339);if($provider==='google'){$p=['summary'=>$b['meeting_name'].' with '.$b['attendee_name'],'description'=>'Booked through OpenCRM. Contact: '.$b['attendee_email'],'start'=>['dateTime'=>$start,'timeZone'=>$b['timezone']],'end'=>['dateTime'=>$end,'timeZone'=>$b['timezone']],'attendees'=>[['email'=>$b['attendee_email']]],'location'=>$b['location_details']];if($b['location_type']==='video')$p['conferenceData']=['createRequest'=>['requestId'=>'opencrm-'.$b['id'].'-'.bin2hex(random_bytes(4)),'conferenceSolutionKey'=>['type'=>'hangoutsMeet']]];return $p;}$p=['subject'=>$b['meeting_name'].' with '.$b['attendee_name'],'body'=>['contentType'=>'text','content'=>'Booked through OpenCRM. Contact: '.$b['attendee_email']],'start'=>['dateTime'=>(new DateTimeImmutable($start))->setTimezone(new DateTimeZone('UTC'))->format('Y-m-d\TH:i:s'),'timeZone'=>'UTC'],'end'=>['dateTime'=>(new DateTimeImmutable($end))->setTimezone(new DateTimeZone('UTC'))->format('Y-m-d\TH:i:s'),'timeZone'=>'UTC'],'attendees'=>[['emailAddress'=>['address'=>$b['attendee_email'],'name'=>$b['attendee_name']],'type'=>'required']],'location'=>['displayName'=>$b['location_details']]];if($b['location_type']==='video'){$p['isOnlineMeeting']=true;$p['onlineMeetingProvider']='teamsForBusiness';}return $p;}
function booking_sync_connection(array $b,array $c,?array $mapping,string $action):array{$provider=$c['provider'];if($provider==='google'){$token=calendar_access_token($c);$calendar=rawurlencode($c['external_calendar_id']?:'primary');$headers=['Authorization: Bearer '.$token,'Content-Type: application/json'];if($action==='delete'){calendar_http('https://www.googleapis.com/calendar/v3/calendars/'.$calendar.'/events/'.rawurlencode($mapping['external_event_id']),'DELETE',$headers);return ['id'=>$mapping['external_event_id'],'url'=>null];}$url='https://www.googleapis.com/calendar/v3/calendars/'.$calendar.'/events'.($mapping?'/'.rawurlencode($mapping['external_event_id']):'?conferenceDataVersion=1');$result=calendar_http($url,$mapping?'PATCH':'POST',$headers,json_encode(booking_provider_payload($b,'google')))['data'];$meeting='';foreach($result['conferenceData']['entryPoints']??[] as $ep)if(($ep['entryPointType']??'')==='video')$meeting=$ep['uri']??'';return ['id'=>(string)($result['id']??$mapping['external_event_id']??''),'url'=>$meeting?:($result['htmlLink']??null),'meeting'=>$meeting];}if($provider==='microsoft'){$token=calendar_access_token($c);$headers=['Authorization: Bearer '.$token,'Content-Type: application/json'];if($action==='delete'){calendar_http('https://graph.microsoft.com/v1.0/me/events/'.rawurlencode($mapping['external_event_id']),'DELETE',$headers);return ['id'=>$mapping['external_event_id'],'url'=>null];}$url='https://graph.microsoft.com/v1.0/me/events'.($mapping?'/'.rawurlencode($mapping['external_event_id']):'');$result=calendar_http($url,$mapping?'PATCH':'POST',$headers,json_encode(booking_provider_payload($b,'microsoft')))['data'];return ['id'=>(string)($result['id']??$mapping['external_event_id']??''),'url'=>$result['webLink']??null,'meeting'=>$result['onlineMeeting']['joinUrl']??''];}$target=$mapping['external_event_id']??rtrim((string)$c['external_calendar_id'],'/').'/opencrm-'.$b['id'].'.ics';$headers=['Authorization: Basic '.base64_encode($c['account_email'].':'.decrypt_secret((string)$c['access_token_enc'])),'Content-Type: text/calendar; charset=utf-8'];if($action==='delete'){calendar_http($target,'DELETE',$headers);return ['id'=>$target,'url'=>null];}calendar_http($target,'PUT',$headers,booking_ical($b,'opencrm-'.$b['id'].'@'.(parse_url((string)config('url'),PHP_URL_HOST)?:'localhost')));return ['id'=>$target,'url'=>$target];}
function booking_sync_calendars(int $bookingId,string $action='upsert'):void{booking_assign_round_robin($bookingId);$b=booking_sync_row($bookingId);if($b['status']==='cancelled')$action='delete';$users=booking_sync_users($b);if(!$users){db()->prepare("UPDATE bookings SET calendar_sync_status='synced',calendar_sync_error=NULL WHERE id=?")->execute([$bookingId]);return;}$placeholders=implode(',',array_fill(0,count($users),'?'));$q=db()->prepare("SELECT * FROM calendar_connections WHERE active=1 AND user_id IN ($placeholders)");$q->execute($users);$connections=$q->fetchAll();$success=0;$errors=[];$meeting='';foreach($connections as $c){$m=db()->prepare('SELECT * FROM booking_calendar_events WHERE booking_id=? AND connection_id=?');$m->execute([$bookingId,$c['id']]);$mapping=$m->fetch()?:null;try{$result=booking_sync_connection($b,$c,$mapping,$action);if($action==='delete')db()->prepare("UPDATE booking_calendar_events SET sync_status='deleted',last_error=NULL,last_synced_at=NOW() WHERE booking_id=? AND connection_id=?")->execute([$bookingId,$c['id']]);else db()->prepare("INSERT INTO booking_calendar_events(booking_id,connection_id,external_event_id,external_url,sync_status,last_synced_at) VALUES(?,?,?,?,'synced',NOW()) ON DUPLICATE KEY UPDATE external_event_id=VALUES(external_event_id),external_url=VALUES(external_url),sync_status='synced',last_error=NULL,last_synced_at=NOW()")->execute([$bookingId,$c['id'],$result['id'],$result['url']]);$meeting=$meeting?:($result['meeting']??'');$success++;}catch(Throwable $e){$errors[]=$c['provider'].': '.$e->getMessage();if($mapping)db()->prepare("UPDATE booking_calendar_events SET sync_status='failed',last_error=? WHERE id=?")->execute([mb_strimwidth($e->getMessage(),0,1000),$mapping['id']]);app_log('error','Booking calendar write-back failed',['booking_id'=>$bookingId,'connection_id'=>$c['id'],'error'=>$e->getMessage()]);}}$status=!$errors?'synced':($success?'partial':'failed');db()->prepare('UPDATE bookings SET meeting_url=COALESCE(NULLIF(?,\'\'),meeting_url),calendar_sync_status=?,calendar_sync_error=? WHERE id=?')->execute([$meeting,$status,$errors?mb_strimwidth(implode(' | ',$errors),0,1000):null,$bookingId]);if($meeting&&$meeting!==($b['meeting_url']??''))try{crm_send_email($b['attendee_email'],'Video link: '.$b['meeting_name'],"Your meeting link is ready:\n\n".$meeting);}catch(Throwable $e){} }

$syncBookingBefore=0;$syncSnapshot=null;
if($method==='POST'&&preg_match('#^/book/[a-z0-9_-]+$#',$path)){$syncBookingBefore=(int)db()->query('SELECT COALESCE(MAX(id),0) FROM bookings')->fetchColumn();register_shutdown_function(function()use($syncBookingBefore){$q=db()->prepare('SELECT id FROM bookings WHERE id>? ORDER BY id');$q->execute([$syncBookingBefore]);foreach($q->fetchAll(PDO::FETCH_COLUMN) as $id)try{booking_sync_calendars((int)$id);}catch(Throwable $e){app_log('error','New booking sync failed',['booking_id'=>$id,'error'=>$e->getMessage()]);}});}
if($method==='POST'&&preg_match('#^/booking/([a-f0-9]{64})$#',$path,$match)){$q=db()->prepare('SELECT id,status,starts_at,ends_at FROM bookings WHERE cancel_token=?');$q->execute([$match[1]]);$syncSnapshot=$q->fetch();if($syncSnapshot)register_shutdown_function(function()use($syncSnapshot){$q=db()->prepare('SELECT status,starts_at,ends_at FROM bookings WHERE id=?');$q->execute([$syncSnapshot['id']]);$after=$q->fetch();if($after&&$after!=$syncSnapshot)try{booking_sync_calendars((int)$syncSnapshot['id'],$after['status']==='cancelled'?'delete':'upsert');}catch(Throwable $e){app_log('error','Booking lifecycle sync failed',['booking_id'=>$syncSnapshot['id'],'error'=>$e->getMessage()]);}});}
